import os
import openpyxl

def move_xlsx(src_dir, dest_dir):
    for root, dirs, files in os.walk(src_dir):
        for f in files:
            if f.endswith('.xlsx'):
                filepath = os.path.join(root, f)
                newpath = os.path.join(dest_dir, f)
                os.rename(filepath, newpath)

def process_xlsx(xlsx_path):
    wb = openpyxl.load_workbook(xlsx_path)
    for ws in wb:
        process_sheet(ws)
    wb.save(xlsx_path)

def process_sheet(ws):
    for row in ws.iter_rows():
        for cell in row:
            cell.value = cell.value.title()

def main():
    src_dir = '/path/to/data/submissions'
    dest_dir = '/path/to/data/processed'
    move_xlsx(src_dir, dest_dir)
    for filepath in os.listdir(dest_dir):
        if filepath.endswith('.xlsx'):
            process_xlsx(os.path.join(dest_dir, filepath))

if __name__ == '__main__':
    main()

