from enum import Enum
from typing import Optional

class Role(Enum):
    admin = 1
    user = 2

class User:
    def __init__(self, name: str, role: Role):
        self.name = name
        self.role = role
        self.dues = 0
        self.projects = []

    def pay_dues(self, amount: int):
        if self.dues < amount:
            raise ValueError("Insufficient dues balance")
        self.dues -= amount

    def add_project(self, project):
        self.projects.append(project)
        project.members.append(self.name)

    def remove_project(self, project):
        self.projects.remove(project)
        project.members.remove(self.name)

class Project:
    def __init__(self, name: str, owner: str):
        self.name = name
        self.owner = owner
        self.members = []

    def add_member(self, user: User) -> None:
        if self.owner == user.name:
            raise ValueError("User is already owner")
        if user.name in self.members:
            raise ValueError("User is already a member")
        user.add_project(self)

    def kick_member(self, member_name: str, kicker: User) -> Optional[bool]:
        if member_name == self.owner:
            raise ValueError("Cannot kick owner")

        if member_name in self.members:
            if kicker.role == Role.admin:
                for member in kicker.projects[0].members:
                    if member_name == member:
                        member.remove_project(self)
                        break
                return True
        return None

